SELECT id
FROM MIS_USER
WHERE username = #{username}
  AND password = #{password}

SELECT id, username, password, name, sex, tel, email, dept_id as deptId, job, ref_id as refId, status, create_time as createTime FROM MIS_USER
WHERE 1=1

    AND username LIKE CONCAT('%', #{username}, '%')


    AND name LIKE CONCAT('%', #{name}, '%')


    AND dept_id = #{deptId}


    AND status = #{status}

ORDER BY id ASC

    LIMIT #{start}, #{length}

SELECT COUNT(*) FROM MIS_USER
WHERE 1=1

    AND username LIKE CONCAT('%', #{username}, '%')


    AND name LIKE CONCAT('%', #{name}, '%')


    AND dept_id = #{deptId}


    AND status = #{status}

mapper.update:
UPDATE MIS_USER SET
password = #{password},
name = #{name}, sex = #{sex}, tel = #{tel}, email = #{email}, dept_id = #{deptId}, job = #{job}, ref_id = #{refId}, status = #{status} WHERE id = #{id}

mapper.select:
SELECT DISTINCT u.id, u.name, u.sex, u.tel, u.email, d.name AS dept, u.job, u.status, role.roles, u.username FROM MIS_USER u LEFT JOIN MIS_DEPT d ON u.dept_id = d.id LEFT JOIN (select ur.user_id,GROUP_CONCAT(r.role_name separator "，" ) roles from MIS_USER_ROLE ur,MIS_ROLE r where ur.role_id = r.id group by ur.user_id) role on u.id = role.user_id WHERE 1 = 1
AND u.name LIKE CONCAT("%",#{name},"%")
AND u.sex = #{sex}
AND u.dept_id = #{deptId}
ORDER BY u.id LIMIT #{start}, #{length}

SELECT COUNT(*) FROM MIS_USER u LEFT JOIN MIS_DEPT d ON u.dept_id = d.id LEFT JOIN (select ur.user_id,GROUP_CONCAT(r.role_name separator "，" ) roles from MIS_USER_ROLE ur,MIS_ROLE r where ur.role_id = r.id group by ur.user_id) role on u.id = role.user_id WHERE 1 = 1
AND u.name LIKE CONCAT("%",#{name},"%")
AND u.sex = #{sex}
AND u.dept_id = #{deptId}
